import{_ as l,H as a,f as t,i as e}from"./chunks/framework.eFU6Tutu.js";const r="/assets/stewed_vegetables.DTEdKc79.jpg",d="/assets/spinach_tomato_salad.CHPI3VAi.jpg",h="/assets/eggs_bacon_tomatoes.Dv4TERrD.jpg",f=JSON.parse('{"title":"Рецепты из томатов черри","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/tomatoes.md","filePath":"recipes/tomatoes.md"}'),o={name:"recipes/tomatoes.md"};function s(n,i,c,p,b,m){return a(),t("div",null,[...i[0]||(i[0]=[e('<h1 id="рецепты-из-томатов-черри" tabindex="-1">Рецепты из томатов черри <a class="header-anchor" href="#рецепты-из-томатов-черри" aria-label="Permalink to &quot;Рецепты из томатов черри&quot;">​</a></h1><h2 id="тушеные-овощи-на-сковороде" tabindex="-1">Тушеные овощи на сковороде <a class="header-anchor" href="#тушеные-овощи-на-сковороде" aria-label="Permalink to &quot;Тушеные овощи на сковороде&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-6-порции" tabindex="-1">Ингредиенты (на 6 порций) <a class="header-anchor" href="#ингредиенты-на-6-порции" aria-label="Permalink to &quot;Ингредиенты (на 6 порций)&quot;">​</a></h3><ul><li>Цукини (или кабачок) — 1 шт.</li><li>Болгарский перец — 1 шт.</li><li>Морковь — 1 шт.</li><li>Лук репчатый — 1 шт.</li><li>Помидоры черри — 12 шт.</li><li>Подсолнечное масло — 1 ст. ложка</li><li>Соль — по вкусу</li><li>Итальянские травы — по вкусу</li></ul></div><div><p><img src="'+r+'" alt="Тушеные овощи на сковороде"></p></div></div><h3 id="пищевая-ценность-на-1-порцию" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>1 г</td><td>2 г</td><td>5 г</td><td>39</td></tr></tbody></table><h3 id="приготовление" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 30 мин</p><ol><li>Цукини вымойте, при желании снимите кожуру. Нарежьте крупными полукольцами.</li><li>Болгарский перец вымойте, удалите семена и плодоножку. Нарежьте крупными кусочками.</li><li>Морковь очистите и нарежьте тонкими полукольцами.</li><li>Лук очистите и нарежьте тонкими полукольцами.</li><li>Помидоры черри вымойте и нарежьте тонкими колечками.</li><li>На сковороде разогрейте растительное масло. Выложите все овощи.</li><li>Добавьте соль и итальянские травы.</li><li>Тушите под закрытой крышкой на среднем огне 5 минут.</li><li>Снимите крышку и доведите овощи до готовности (ещё 5-7 минут).</li></ol><h2 id="салат-со-шпинатом-и-помидорами" tabindex="-1">Салат со шпинатом и помидорами <a class="header-anchor" href="#салат-со-шпинатом-и-помидорами" aria-label="Permalink to &quot;Салат со шпинатом и помидорами&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-1-порцию" tabindex="-1">Ингредиенты (на 1 порцию) <a class="header-anchor" href="#ингредиенты-на-1-порцию" aria-label="Permalink to &quot;Ингредиенты (на 1 порцию)&quot;">​</a></h3><ul><li>Шпинат — 50 г</li><li>Яйца — 1 шт.</li><li>Помидоры черри — 6 шт.</li><li>Кукуруза консервированная — 40 г</li><li>Растительное масло — 2 ст. ложки</li><li>Бальзамический уксус — 1 ч. ложка</li><li>Соль — по вкусу</li></ul></div><div><p><img src="'+d+'" alt="Салат со шпинатом и помидорами"></p></div></div><h3 id="пищевая-ценность-на-1-порцию-1" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию-1" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>4 г</td><td>12 г</td><td>4 г</td><td>138</td></tr></tbody></table><h3 id="приготовление-1" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-1" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 20 мин</p><ol><li>Яйцо отварите вкрутую, остудите и очистите.</li><li>Шпинат переберите, промойте и обсушите.</li><li>Помидоры черри вымойте и обсушите.</li><li>В небольшой миске смешайте растительное масло с бальзамическим уксусом.</li><li>Шпинат порвите руками на куски и выложите в салатник.</li><li>Кукурузу откиньте на сито, чтобы удалить жидкость, и добавьте к шпинату.</li><li>Черри разрежьте на 4 части, выложите сверху.</li><li>Яйцо разрежьте на 4-6 частей, уложите в салатник, посолите.</li><li>Полейте салат заправкой.</li></ol><h2 id="яичница-с-беконом-и-томатами-черри" tabindex="-1">Яичница с беконом и томатами черри <a class="header-anchor" href="#яичница-с-беконом-и-томатами-черри" aria-label="Permalink to &quot;Яичница с беконом и томатами черри&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-4-порции" tabindex="-1">Ингредиенты (на 4 порции) <a class="header-anchor" href="#ингредиенты-на-4-порции" aria-label="Permalink to &quot;Ингредиенты (на 4 порции)&quot;">​</a></h3><ul><li>Бекон — 70 г</li><li>Сливочное масло — 30 г</li><li>Перепелиные яйца — 13 шт.</li><li>Помидоры черри — 7 шт.</li><li>Лук репчатый — 1/3 шт.</li><li>Укроп — по вкусу</li><li>Морская соль — по вкусу</li><li>Перец чёрный молотый — по вкусу</li></ul></div><div><p><img src="'+h+'" alt="Яичница с беконом и томатами черри"></p></div></div><h3 id="пищевая-ценность-на-1-порцию-2" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию-2" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>7 г</td><td>13 г</td><td>2 г</td><td>196</td></tr></tbody></table><h3 id="приготовление-2" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-2" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 10 мин</p><ol><li>Лук нарежьте мелкими кубиками.</li><li>Бекон нарежьте небольшими кусочками.</li><li>На сковороде разогрейте сливочное масло.</li><li>Обжарьте лук до прозрачности.</li><li>Добавьте бекон и слегка обжарьте.</li><li>Помидоры черри разрежьте на 4 части.</li><li>Укроп мелко нарежьте.</li><li>Разбейте в сковороду перепелиные яйца, стараясь не повредить желток.</li><li>Добавьте соль и перец по вкусу.</li><li>Готовьте на среднем огне 5 минут.</li><li>Посыпьте готовую яичницу укропом.</li></ol><h2 id="другие-рецепты" tabindex="-1">Другие рецепты <a class="header-anchor" href="#другие-рецепты" aria-label="Permalink to &quot;Другие рецепты&quot;">​</a></h2><ul><li><a href="/recipes/peppers.html">Рецепты с перцами</a></li><li><a href="/recipes/mint.html">Мята</a></li><li><a href="/recipes/basil.html">Базилик</a></li></ul>',24)])])}const _=l(o,[["render",s]]);export{f as __pageData,_ as default};
